    /**
    Write a function that takes a message, and encodes in such a 
    way that it swaps case of all letters, replaces all vowels in 
    the message with the letter that appears 2 places ahead of that 
    vowel in the english alphabet. 
    Assume only letters. 

    Examples:
    >>> encode('test')
    'tEst'
    >>> encode('This is a message')
    'tHIs IS A MESSAgE'
     */
    public String encode(String message) {

canonical_solution:
        String vowels = "aeiouAEIOU";
        String alphabet = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ";
        StringBuilder sb = new StringBuilder();
        for (char c : message.toCharArray()) {
            if (Character.isLetter(c)) {
                char swappedCase = Character.isUpperCase(c) ? Character.toLowerCase(c) : Character.toUpperCase(c);
                if (vowels.indexOf(swappedCase) != -1) {
                    char nextVowel = (char) (swappedCase + 2);
                    if (Character.toLowerCase(swappedCase) == 'y' || Character.toLowerCase(swappedCase) == 'z') {
                        nextVowel = (char) (swappedCase - 24);
                    }
                    sb.append(nextVowel);
                } else {
                    sb.append(swappedCase);
                }
            } else {
                sb.append(c);
            }
        }
        return sb.toString();
    }
}

